module RefModule(
    output reg X,
    input wire A,
    input wire B,
    input wire C,
    input wire D,
    input wire VPWR,
    input wire VGND,
    input wire VPB,
    input wire VNB
);wire or_output;

    // Simple four-input OR gate implementation
    wire __or_output_tmp = A | B | C | D;
    assign or_output = __or_output_tmp;

    always @ (or_output) begin
        X = or_output;
    end

endmodule
